function curLang(){return localStorage.getItem('goalify_lang')||'en';}
function langSelect(){const cur=curLang();return `<select id="langSel" class="input !py-1.5 text-xs" title="Language">${LANGS.map(l=>`<option value="${l[0]}" ${cur===l[0]?'selected':''}>${l[2]||'🌐'} ${l[1]}</option>`).join('')}</select>`;}
function translateDOM(root){
  const lang=curLang();if(lang==='en')return;const dict=I18N[lang];if(!dict||!root)return;
  const w=document.createTreeWalker(root,NodeFilter.SHOW_TEXT,null);const nodes=[];
  while(w.nextNode())nodes.push(w.currentNode);
  nodes.forEach(n=>{const raw=n.nodeValue,key=raw.trim();if(key&&dict[key])n.nodeValue=raw.replace(key,dict[key]);});
}
let _i18nObs;
function startI18n(){
  const root=document.getElementById('root');if(!root)return;translateDOM(root);
  if(_i18nObs)return;
  _i18nObs=new MutationObserver(()=>{_i18nObs.disconnect();translateDOM(root);_i18nObs.observe(root,{childList:true,subtree:true});});
  _i18nObs.observe(root,{childList:true,subtree:true});
}
function setLang(l){localStorage.setItem('goalify_lang',l);render();}
function planNav(plan){
  const c=caps(plan);
  const nav=[['dashboard','Dashboard','📊'],['goals','Goals','🎯']];
  if(c.analytics){nav.push(['analytics','Analytics','📈'],['simulator','Future Simulator','🔮'],['spendcalc','Impact Calculator','💸']);}
  if(c.gamify)nav.push(['challenges','Challenges','🏆']);
  if(c.social!=='none')nav.push(['social','Social','👥']);
  nav.push(['profile','Profile','🪪']);
  nav.push(['rewards','Rewards','🎁']);
  nav.push(['plans','Plans','💳']);
  if(plan==='free')nav.push(['student','Student Verify','🎓']);
  nav.push(['settings','Settings','⚙️']);
  return nav;
}


