  shopping:{Kosovo:25,Albania:25,'North Macedonia':28,Serbia:30,Greece:40,Spain:45,Italy:50,France:55,Germany:55,Netherlands:55,'United Kingdom':55,Ireland:60,'United States':62,Switzerland:85,Other:45},
