  const lbls=ent.map(([k])=>catLabel(k)),data=ent.map(([,v])=>v);
  const palette=['#8b5cf6','#6366f1','#22c55e','#f59e0b','#ec4899','#3b82f6','#ef4444','#14b8a6'];
  if(charts.quiz)charts.quiz.destroy();
